using NewSmartAIFactory.CompanyApi.Models;using NewSmartAIFactory.CompanyApi.Services;
namespace NewSmartAIFactory.CompanyApi.Endpoints;
public static class EventEndpoints{public static IEndpointRouteBuilder MapEventEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/events").WithTags("Events");g.MapGet("/",async(string? projectId,string? eventType,int? limit,EventStoreService s,CancellationToken t)=>Results.Ok(await s.ListAsync(projectId,eventType,limit??50,t)));g.MapPost("/",async(CreateDomainEventRequest r,EventStoreService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.EventType)||string.IsNullOrWhiteSpace(r.AggregateType)||string.IsNullOrWhiteSpace(r.AggregateId))return Results.BadRequest(new{error="required_fields",message="EventType, aggregateType, and aggregateId are required."});var e=await s.AppendAsync(r,t);return Results.Created($"/api/events/{e.Id}",e);});g.MapPost("/{id:guid}/publish",async(Guid id,EventStoreService s,CancellationToken t)=>{var published=await s.PublishAsync(id,t);return published?Results.Ok(await s.ListAsync(null,null,200,t).ContinueWith(x=>x.Result.First(e=>e.Id==id),t)):Results.NotFound(new{error="publish_failed",message="Event was not found or RabbitMQ publish failed."});});return app;}}
